const n={root:null,rootMargin:"-50% 0px -50% 0px",threshold:0},s=new IntersectionObserver(e=>{e.forEach(t=>{if(t.isIntersecting){document.querySelectorAll(".nav-link").forEach(r=>{r.classList.remove("active")});const c=t.target.id,o=document.querySelector(`.nav-link[data-section="${c}"]`);o&&o.classList.add("active")}})},n);document.querySelectorAll("section[id]").forEach(e=>{s.observe(e)});
